 1	import React, { FC } from 'react';
 2	import { Link } from 'react-router-dom-v5-compat';
 3	
 4	import { IngressModel, modelToRef } from '@kubevirt-ui/kubevirt-api/console';
 5	import { IoK8sApiNetworkingV1Ingress } from '@kubevirt-ui/kubevirt-api/kubernetes/models';
 6	import {
 7	  Breadcrumb,
 8	  BreadcrumbItem,
 9	  Flex,
10	  FlexItem,
11	  PageSection,
12	  PageSectionVariants,
13	  Stack,
14	  Title,
15	} from '@patternfly/react-core';
16	import { useLastNamespacePath } from '@utils/hooks/useLastNamespacePath';
17	import { useNetworkingTranslation } from '@utils/hooks/useNetworkingTranslation';
18	import { getName } from '@utils/resources/shared';
19	import IngressActions from '@views/ingresses/actions/IngressActions';
20	
21	import './IngressDetailsPageTitle.scss';
22	
23	type IngressDetailsPageTitleProps = {
24	  ingress: IoK8sApiNetworkingV1Ingress;
25	};
26	
27	const IngressDetailsPageTitle: FC<IngressDetailsPageTitleProps> = ({ ingress }) => {
28	  const { t } = useNetworkingTranslation();
29	  const namespacePath = useLastNamespacePath();
30	
31	  return (
32	    <PageSection className="co-m-nav-title--detail" variant={PageSectionVariants.light}>
33	      <Breadcrumb className="pf-c-breadcrumb co-breadcrumb ingress-details-breadcrumbs">
34	        <BreadcrumbItem>
35	          <Link to={`/k8s/${namespacePath}/${modelToRef(IngressModel)}`}>{t('Ingresses')}</Link>
36	        </BreadcrumbItem>
37	        <BreadcrumbItem>{t('Ingress details')}</BreadcrumbItem>
38	      </Breadcrumb>
39	      <Stack hasGutter>
40	        <Flex justifyContent={{ default: 'justifyContentSpaceBetween' }}>
41	          <FlexItem>
42	            <Title className="co-resource-item__resource-name" headingLevel="h1">
43	              <span className="co-m-resource-icon co-m-resource-icon--lg">
44	                {t(IngressModel?.abbr)}
45	              </span>
46	              {getName(ingress)}
47	            </Title>
48	          </FlexItem>
49	          <FlexItem>
50	            <IngressActions ingress={ingress} />
51	          </FlexItem>
52	        </Flex>
53	      </Stack>
54	    </PageSection>
55	  );
56	};
57	
58	export default IngressDetailsPageTitle;

